function seedSkillsIfEmpty(){
  // If any hierarchical skills exist, leave them alone — but still add any NEW seed
  // skills that didn't exist before (so updates introduce new skills without wiping progress).
  if(S.lifeSkills && S.lifeSkills.some(s=>s.group||s.parent!==undefined)){
    mergeNewSeedSkills();
    return;
  }
  // Old flat skills (no hierarchy fields) -> replace with the new tree.
  // Empty list (even if _seeded was set by an old version) -> seed fresh.
  S.lifeSkills=SEED_SKILLS.map(s=>({
    id:id(), name:s.name, cat:s.cat, parent:s.parent||null, group:!!s.group,
    fadeDays:s.fadeDays, auto:s.auto||null,
    why:s.why||null, whatYouDo:s.whatYouDo||null, howTo:s.howTo||null, prep:s.prep||null, recover:s.recover||null, safety:s.safety||null,
    roadmap:s.roadmap||null, advance:s.advance||null, maintain:s.maintain||null, tiers:s.tiers||null,
    currentLevel:0, lastQuestTs:Date.now(), peakLevel:0,
    levels:(s.levels||[]).map((ability,i)=>({n:i+1,ability})), history:[], seeded:true
  }));
  S._seeded=true; S._skillLadderVer=SKILL_LADDER_VER; save();
}
// Add seed skills the user doesn't have yet (by name), and backfill transparency copy
// Current seed-ladder version. BUMP THIS whenever any skill's ladder/tiers/guidance
// changes, so an old save (even one many versions behind) force-resyncs all ladder
// CONTENT from the seed on load — while preserving the user's progress numbers
// (currentLevel/peakLevel/history). This is the safety net for stale autosave files.
